#include <stdio.h>
#include <stdlib.h>

void findCombinations(int index, int* arr, int target, int* current, int** result, int* resultSize, int* combinationSize) {
    if (target == 0) {
        int* combination = (int*)malloc((*combinationSize) * sizeof(int));
        for (int i = 0; i < *combinationSize; i++) {
            combination[i] = current[i];
        }
        result[*resultSize] = combination;
        (*resultSize)++;
        return;
    }
    if (index >= 30 || target < 0) {
        return;
    }
    // Include the current number in the combination
    current[(*combinationSize)++] = arr[index];
    findCombinations(index, arr, target - arr[index], current, result, resultSize, combinationSize);
    (*combinationSize)--;
    // Exclude the current number from the combination
    findCombinations(index + 1, arr, target, current, result, resultSize, combinationSize);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int target;
        scanf("%d", &target);
        int* current = (int*)malloc(target * sizeof(int));
        int combinationSize = 0;
        int resultSize = 0;
        int** result = (int**)malloc(1000 * sizeof(int*));
        findCombinations(0, arr, target, current, result, &resultSize, &combinationSize);
        if (resultSize == 0) {
            printf("[]\n");
        } else {
            for (int i = 0; i < resultSize; i++) {
                for (int j = 0; j < combinationSize; j++) {
                    printf("%d ", result[i][j]);
                }
                printf("\n");
            }
        }
    }
    return 0;
}

