#include <iostream>
#include <vector>
using namespace std;

void findCombinations(int index, vector<int>& arr, int target, vector<int>& current, vector<vector<int>>& result) {
    if (target == 0) {
        result.push_back(current);
        return;
    }
    if (index >= arr.size() || target < 0) {
        return;
    }
    // Include the current number in the combination
    current.push_back(arr[index]);
    findCombinations(index, arr, target - arr[index], current, result);
    current.pop_back();
    // Exclude the current number from the combination
    findCombinations(index + 1, arr, target, current, result);
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        vector<int> arr(N);
        for (int i = 0; i < N; i++) {
            cin >> arr[i];
        }
        int target;
        cin >> target;
        vector<int> current;
        vector<vector<int>> result;
        findCombinations(0, arr, target, current, result);
        if (result.size() == 0) {
            cout << "[]\n";
        } else {
            for (const auto& combination : result) {
                for (int num : combination) {
                    cout << num << " ";
                }
                cout << endl;
            }
        }
    }
    return 0;
}

code.Java:
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class Main {
    public static void findCombinations(int index, int[] arr, int target, List<Integer> current, List<List<Integer>> result) {
        if (target == 0) {
            result.add(new ArrayList<>(current));
            return;
        }
        if (index >= arr.length || target < 0) {
            return;
        }
        // Include the current number in the combination
        current.add(arr[index]);
        findCombinations(index, arr, target - arr[index], current, result);
        current.remove(current.size() - 1);
        // Exclude the current number from the combination
        findCombinations(index + 1, arr, target, current, result);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = scanner.nextInt();
            }
            int target = scanner.nextInt();
            List<Integer> current = new ArrayList<>();
            List<List<Integer>> result = new ArrayList<>();
            findCombinations(0, arr, target, current, result);
            if (result.size() == 0) {
                System.out.println("[]");
            } else {
                for (List<Integer> combination : result) {
                    for (int num : combination) {
                        System.out.print(num + " ");
                    }
                    System.out.println();
                }
            }
        }
    }
}

